    pages.push(page(2,'Агуулга',`<div class="toc-row"><span>1. Үйлчлүүлэгчийн мэдээлэл</span><span class="dots"></span><b>1</b></div><div class="toc-row"><span>2. Гол дүгнэлт</span><span class="dots"></span><b>2</b></div><div class="toc-row"><span>3. Жил, махбод, ордын нийлэмж</span><span class="dots"></span><b>3</b></div><div class="toc-row"><span>4. Энергийн матрицын суурь</span><span class="dots"></span><b>4</b></div><div class="toc-row"><span>5. Төв ба сэтгэлийн энерги</span><span class="dots"></span><b>5</b></div><div class="toc-row"><span>6. Санхүү, мөнгөний урсгал</span><span class="dots"></span><b>6</b></div><div class="toc-row"><span>7. Ажил, карьер</span><span class="dots"></span><b>7</b></div><div class="toc-row"><span>8. Бизнес, хөрөнгө оруулалт</span><span class="dots"></span><b>8</b></div><div class="toc-row"><span>9. Хайр, ханийн заяа</span><span class="dots"></span><b>9</b></div><div class="toc-row"><span>10. Гэр бүл, үр хүүхэд</span><span class="dots"></span><b>10</b></div><div class="toc-row"><span>11. Эрүүл мэнд</span><span class="dots"></span><b>11</b></div><div class="toc-row"><span>12. Насны мөчлөг</span><span class="dots"></span><b>12</b></div><div class="toc-row"><span>13. Ирэх 3 жилийн төлөв</span><span class="dots"></span><b>13</b></div><div class="toc-row"><span>14. Засал, сахиус</span><span class="dots"></span><b>14</b></div><div class="toc-row"><span>15. Төлбөрийн мэдээлэл</span><span class="dots"></span><b>15</b></div><div class="toc-row"><span>16. Ерөнхий ерөөл</span><span class="dots"></span><b>16</b></div>`));
    pages.push(page(3,'Гол дүгнэлт',ptag(`Амар амгаланг айлтгая. ${txt(pr.name)} нь ${txt(pr.color)} ${txt(pr.animal)} жилийн <b>${txt(A.core)}</b> чанарыг, ${txt(pr.elem)} махбодын <b>${txt(E.core)}</b> өнгийг хамтад нь тээсэн байна. Төв энерги <b>${pr.m.base} — ${txt(e0.name)}</b> тул амьдралын гол учиг нь ${txt(e0.core)}.`)+ptag(`Одоогийн ${pr.age} насны мөчлөг дээр <b>${txt(ec.name)}</b> чанар идэвхжиж байна. Энэ нь өмнөх туршлагаа ашиглаж, амьдралын дараагийн сууриа илүү тодорхой тавих цаг үе гэсэн үг.`)+emphasizedTopicText(pr)+bullet([`Гол хүч: ${txt(e0.light)}.`,`Анхаарах зангилаа: ${txt(e0.shadow)}.`,`Гэрлэлтийн байдлаар: ${txt(statusAdvice(pr.status))}.`])));
    pages.push(page(4,'Жил, махбод, ордын нийлэмж',ptag(`${txt(pr.animal)} жилийн суурь чанар: ${txt(A.core)}. Ажил үйлд ${txt(A.work)}. Санхүүд ${txt(A.money)}. Харилцаанд ${txt(A.love)}. Эрүүл мэндийн өнгөөр ${txt(A.health)}.`)+ptag(`${txt(pr.elem)} махбодын нөлөө: ${txt(E.core)}. ${txt(E.spirit)} Өрнийн ${txt(pr.wname)} орд нь ${txt(pr.wtext)} чанарыг нэмдэг тул дорнын жилтэй нийлээд шийдвэр гаргах арга, харилцах хэлбэрт өөрийн өнгө оруулна.`)+bullet([`Жилийн болгоомжлол: ${txt(A.warn)}.`,`Махбодын ажил хэрэг: ${txt(E.work)}.`,`Махбодын мөнгөний өнгө: ${txt(E.money)}.`])));
    pages.push(page(5,'Энергийн матрицын суурь',ptag(`Энергийн матриц нь төрсөн огноо, нэр, насны хэмнэлээс гарсан туслах тайлал юм. Энэ нь хүнийг айлгах зүйл биш, харин сэтгэл, ажил, мөнгө, гэр бүл, эрүүл мэндийн аль хэсэгт ямар чанар идэвхтэй байгааг унших арга болно.`)+bullet([`Төв: ${pr.m.base} — ${txt(e0.name)}: ${txt(e0.core)}.`,`Сэтгэл: ${pr.m.heart} — ${txt(eh.name)}: ${txt(eh.love)}.`,`Мөнгө: ${pr.m.money} — ${txt(em.name)}: ${txt(em.money)}.`,`Ажил: ${pr.m.work} — ${txt(ew.name)}: ${txt(ew.work)}.`,`Эрүүл мэнд: ${pr.m.health} — ${txt(ehl.name)}: ${txt(ehl.health)}.`,`Гэр бүл: ${pr.m.family} — ${txt(ef.name)}: ${txt(ef.love)}.`,`Од хийморь: ${pr.m.spirit} — ${txt(es.name)}: ${txt(es.advice)}.`])));
    pages.push(page(6,'Төв ба сэтгэлийн энерги',ptag(`Төв энерги <b>${pr.m.base} — ${txt(e0.name)}</b>: ${moreFromEnergy(e0,'core')}`)+ptag(`Сэтгэлийн энерги <b>${pr.m.heart} — ${txt(eh.name)}</b>: ${moreFromEnergy(eh,'love')}`)+bullet([`Давуу тал: ${txt(eh.light)}.`,`Сүүдэр тал: ${txt(eh.shadow)}.`,`Өдөр тутмын засах арга: ${txt(eh.advice)}.`])));
    pages.push(page(7,'Санхүү, мөнгөний урсгал',ptag(`Мөнгөний матриц <b>${pr.m.money} — ${txt(em.name)}</b>: ${moreFromEnergy(em,'finance')}`)+ptag(`${txt(pr.animal)} жил мөнгөн дээр: ${txt(A.money)} ${txt(pr.elem)} махбодын хувьд: ${txt(E.money)}`)+bullet([`Мөнгө тогтоох арга: ${topicHas(pr,'finance')?'өр, зээл, орлого, зарлагын жагсаалтаа тусад нь гаргаж, хамгийн түрүүнд дарах нэг дарамтаа сонгох':'орлого бүрээс шууд хадгаламж салгах'}.`,`Сэрэмжлэх зүйл: ${txt(pick(pools.warn,pr.s,4))}.`,`Ивээлтэй алхам: нэг тогтмол орлогын суваг дээр төвлөрөх.`])));
    pages.push(page(8,'Ажил, карьер',ptag(`Ажлын матриц <b>${pr.m.work} — ${txt(ew.name)}</b>: ${txt(ew.work)} ${txt(A.work)} ${txt(E.work)}`)+ptag(topicHas(pr,'career')?'Нэмэлт тэмдэглэл ажил, карьерын чиглэл рүү хандсан тул одоо олон санаа хөөхөөс илүү нэг гол чиглэлийн ур чадварыг дээшлүүлж, хүмүүст харуулах багц санал болгох хэрэгтэй.':'Ажил үйлсийн хувьд эхлүүлсэн зүйлээ таслахгүй үргэлжлүүлэх нь хамгийн хүчтэй засал болно.')+bullet([`Давуу тал: ${txt(ew.light)}.`,`Саад: ${txt(ew.shadow)}.`,`Зөв алхам: ${txt(ew.advice)}.`])));
    pages.push(page(9,'Бизнес ба хөрөнгө оруулалт',ptag(`Бизнесийн өнгө нь жил, махбод, мөнгөний матриц гурав нийлж гарна. ${txt(pr.elem)} махбодын хувьд ${txt(E.work)}. ${txt(pr.animal)} жилийн хувьд ${txt(A.work)}`)+bullet([`Бизнесийн боломж: ${txt(pick(['үйлчилгээний багц гаргах','онлайн захиалга, контент, зөвлөгөөтэй холбох','итгэлцэл дээр суурилсан жижиг багц ажил эхлүүлэх','байгаа харилцагчдаа дахин ашиглах санал гаргах'],pr.s,5))}.`,`Хөрөнгө оруулалтын зарчим: ойлгодог зүйлдээ бага багаар, баримттай оролцох.`,`Сэрэмжлэх зүйл: хурдан ашиг амлах зүйл, аман тохиролцоо, тооцоогүй өр зээл.`])));
    pages.push(page(10,'Хайр дурлал, ханийн заяа',ptag(`Сэтгэлийн матриц <b>${pr.m.heart} — ${txt(eh.name)}</b>: ${moreFromEnergy(eh,'love')}`)+ptag(`${txt(A.love)} ${txt(E.love)} ${txt(statusAdvice(pr.status))}`)+bullet([`Хайрын давуу тал: ${txt(pick(['үнэнч, түшигтэй байх','сэтгэлээ үйлдлээр харуулах','гэр бүлийн дулаан орчин хүсэх','хүндээ итгэл өгч чаддаг'],pr.s,6))}.`,`Сорил: ${txt(pick(['дуугүй гомдол хуримтлуулах','хэт шалгах эсвэл хэт итгэх','мөнгөний яриаг хойшлуулах','өнгөрсөн сэтгэлийн шархаа одоогийн хүн дээр гаргах'],pr.s,7))}.`,`Ханийн тэнгэрт хэрэгтэй зүйл: зөөлөн үг, ил тод байдал, хамтын зорилго.`])));
